    questions: [ {q:"Was the real group called the Bavarian Illuminati?", a_en:"Yes", a_tr:"Evet"}, {q:"Did the founder want to promote reason and science?", a_en:"Yes", a_tr:"Evet"}, {q:"Did he like nothing about the power of the church?", a_en:"Yes", a_tr:"Evet"}, {q:"Did the Illuminati last for a very long period?", a_en:"No", a_tr:"Hayır"}, {q:"Did the ruler of Bavaria ban all secret societies in 1785?", a_en:"Yes", a_tr:"Evet"}, {q:"Is there proof that they control the world banks today?", a_en:"No", a_tr:"Hayır"}, {q:"Is the name still used to describe a hidden elite?", a_en:"Yes", a_tr:"Evet"} ]
