    questions: [ {q:"Was the order created to protect the tomb of Jesus?", a_en:"Yes", a_tr:"Evet"}, {q:"Did the leader of the Crusaders form this group of knights?", a_en:"Yes", a_tr:"Evet"}, {q:"Were these knights often nobles who served the King?", a_en:"Yes", a_tr:"Evet"}, {q:"Are they still a fierce military army today?", a_en:"No", a_tr:"Hayır"}, {q:"Does the Pope lead the order today?", a_en:"Yes", a_tr:"Evet"}, {q:"Do they wear white capes with a red cross?", a_en:"Yes", a_tr:"Evet"}, {q:"Is their main job now to send money to support Christians?", a_en:"Yes", a_tr:"Evet"} ]
