    questions: [ {q:"Was the original job of the Templars to protect Christian pilgrims?", a_en:"Yes", a_tr:"Evet"}, {q:"Were they both monks and fierce soldiers?", a_en:"Yes", a_tr:"Evet"}, {q:"Did they create the first international banking system?", a_en:"Yes", a_tr:"Evet"}, {q:"Did their wealth make people happy for them?", a_en:"No", a_tr:"Hayır"}, {q:"Did King Philip IV of France owe them money?", a_en:"Yes", a_tr:"Evet"}, {q:"Did he arrest and torture hundreds of Templars?", a_en:"Yes", a_tr:"Evet"}, {q:"Did the Pope refuse to dissolve the order?", a_en:"No", a_tr:"Hayır"} ]
