    questions: [ {q:"Is the KKK a hate group in the United States?", a_en:"Yes", a_tr:"Evet"}, {q:"Did the founders accept nothing about slavery ending?", a_en:"Yes", a_tr:"Evet"}, {q:"Did they wear pointed hoods to hide their faces?", a_en:"Yes", a_tr:"Evet"}, {q:"Did they use peace and love to spread their message?", a_en:"No", a_tr:"Hayır"}, {q:"Did they burn crosses near people's houses?", a_en:"Yes", a_tr:"Evet"}, {q:"Did they hate immigrants and Catholics too?", a_en:"Yes", a_tr:"Evet"}, {q:"Are they considered a terrorist organization today?", a_en:"Yes", a_tr:"Evet"} ]
