    questions: [ {q:"Were the Livonian Brothers a ruthless order of knights?", a_en:"Yes", a_tr:"Evet"}, {q:"Was their job to convert the pagan people to Christianity?", a_en:"Yes", a_tr:"Evet"}, {q:"Were they known for being very kind?", a_en:"No", a_tr:"Hayır"}, {q:"Did they wear white cloaks with a red sword?", a_en:"Yes", a_tr:"Evet"}, {q:"Did they show no consistent discipline?", a_en:"Yes", a_tr:"Evet"}, {q:"Were they badly defeated by local tribes?", a_en:"Yes", a_tr:"Evet"}, {q:"Is their history full of peace and love?", a_en:"No", a_tr:"Hayır"} ]
