    questions: [ {q:"Is Opus Dei an institution within the Catholic Church?", a_en:"Yes", a_tr:"Evet"}, {q:"Does the name mean 'Work of God' in Latin?", a_en:"Yes", a_tr:"Evet"}, {q:"Do they teach that ordinary work can be a path to holiness?", a_en:"Yes", a_tr:"Evet"}, {q:"Did critics say it offered no transparency?", a_en:"Yes", a_tr:"Evet"}, {q:"Do they practice mortification to feel physical pleasure?", a_en:"No", a_tr:"Hayır"}, {q:"Are they very influential in politics and business?", a_en:"Yes", a_tr:"Evet"}, {q:"Do all people view them with complete trust?", a_en:"No", a_tr:"Hayır"} ]
