    questions: [ {q:"Was the purpose of the order to defend Christianity?", a_en:"Yes", a_tr:"Evet"}, {q:"Did they wear a symbol of a dragon?", a_en:"Yes", a_tr:"Evet"}, {q:"Was the order no secret society like the others?", a_en:"Yes", a_tr:"Evet"}, {q:"Did Vlad II take the name 'Dracul'?", a_en:"Yes", a_tr:"Evet"}, {q:"Was his son the inspiration for the werewolf legend?", a_en:"No", a_tr:"Hayır"}, {q:"Was the order a political tool to keep nobles loyal?", a_en:"Yes", a_tr:"Evet"}, {q:"Did the order become more important after the King died?", a_en:"No", a_tr:"Hayır"} ]
