    questions: [ {q:"Is the Sicilian Mafia also known as Cosa Nostra?", a_en:"Yes", a_tr:"Evet"}, {q:"Did they originally protect land when the police were weak?", a_en:"Yes", a_tr:"Evet"}, {q:"Is their most important rule 'Omertà', the code of silence?", a_en:"Yes", a_tr:"Evet"}, {q:"Can a member talk safely to the authorities?", a_en:"No", a_tr:"Hayır"}, {q:"Did many members move to the United States?", a_en:"Yes", a_tr:"Evet"}, {q:"Were they involved in gambling and smuggling?", a_en:"Yes", a_tr:"Evet"}, {q:"Is the Mafia completely destroyed today?", a_en:"No", a_tr:"Hayır"} ]
