    questions: [ {q:"Did the Teutonic Knights start by running a hospital?", a_en:"Yes", a_tr:"Evet"}, {q:"Did they wear white coats with a black cross?", a_en:"Yes", a_tr:"Evet"}, {q:"Did they launch the Northern Crusades?", a_en:"Yes", a_tr:"Evet"}, {q:"Were they no mere monks but actual rulers?", a_en:"Yes", a_tr:"Evet"}, {q:"Did they ask nicely for people to change religion?", a_en:"No", a_tr:"Hayır"}, {q:"Were they defeated at the Battle of Tannenberg?", a_en:"Yes", a_tr:"Evet"}, {q:"Do they still exist today as a charitable organization?", a_en:"Yes", a_tr:"Evet"} ]
